{"name":"index.ts","startLine":49,"endLine":159,"content":"export function executeTuff(tuffSourceCode: string): number | bigint {
  if (tuffSourceCode === "") {
    return 0;
  }

  // Tokenize by splitting on whitespace, then further split parentheses from literals
  const rawTokens = tuffSourceCode.trim().split(/\s+/);
  const tokens: string[] = [];
  for (const raw of rawTokens) {
    // Split leading/trailing parens off each token
    let remaining = raw;
    while (remaining.startsWith("(")) {
      tokens.push("(");
      remaining = remaining.slice(1);
    }
    if (!remaining) continue;
    const trailingParens = [];
    while (remaining.endsWith(")")) {
      trailingParens.unshift(")");
      remaining = remaining.slice(0, -1);
    }
    tokens.push(remaining);
    for (const p of trailingParens) {
      tokens.push(p);
    }
  }

  let pos = 0;

  function peek(): string | undefined {
    return tokens[pos];
  }

  function consume(): string {
    return tokens[pos++]!;
  }

  function normalizeResult(val: bigint): number | bigint {
    if (val <= Number.MAX_SAFE_INTEGER && val >= -Number.MAX_SAFE_INTEGER) {
      return Number(val);
    }
    return val;
  }

  // Recursive descent parser with operator precedence: * / before + -
  function parseTerm(): number | bigint {
    let left: bigint;
    if (peek() === "(") {
      consume(); // consume '('
      const exprResult = BigInt(parseExpr());
      if (peek() !== ")") throw new Error("Invalid format");
      consume(); // consume ')'
      left = exprResult;
    } else {
      left = BigInt(parseLiteral(consume()));
    }
    while (peek() === "*" || peek() === "/") {
      const op = consume();
      const right = BigInt(parseTerm());
      if (op === "*") left *= right;
      else {
        if (right === 0n) throw new Error("Division by zero");
        left /= right;
      }
    }
    return normalizeResult(left);
  }

  function parseExpr(): number | bigint {
    let left = BigInt(parseTerm());
    while (peek() === "+" || peek() === "-") {
      const op = consume();
      const right = BigInt(parseTerm());
      if (op === "+") left += right;
      else left -= right;
    }
    return normalizeResult(left);
  }

  const result = parseExpr();

  if (pos < tokens.length) {
    throw new Error("Invalid format");
  }

  return result;
}
"}

