{"name":"index.ts","startLine":80,"endLine":145,"content":"let pos = 0;

  function peek(): string | undefined {
    return tokens[pos];
  }

  function consume(expected?: string): string {
    const token = tokens[pos++]!;
    if (expected && token !== expected) throw new Error("Invalid format");
    return token;
  }

  function normalizeResult(val: bigint): number | bigint {
    if (val <= Number.MAX_SAFE_INTEGER && val >= -Number.MAX_SAFE_INTEGER) {
      return Number(val);
    }
    return val;
  }

  // Variable scope for let declarations inside blocks
  const scope = new Map<string, bigint>();

  function parseIdentifier(): string {
    const name = consume();
    if (!scope.has(name)) throw new Error(`Undefined variable: ${name}`);
    return name;
  }

  // Recursive descent parser with operator precedence: * / before + -
  function parseTerm(): number | bigint {
    let left: bigint;
    const token = peek();
    if (token === "(") {
      consume("(");
      const exprResult = BigInt(parseExpr());
      consume(")");
      left = exprResult;
    } else if (token === "{") {
      consume("{");
      // Parse block: sequence of statements separated by ;, last expression is the value
      let result: bigint | undefined;
      while (!peek() || peek() !== "}") {
        const stmtResult = parseStatement();
        result = BigInt(stmtResult);
      }
      consume("}");
      left = result!;
    } else if (token && /^[a-zA-Z_]\w*$/.test(token)) {
      // Variable reference
      const name = parseIdentifier();
      left = scope.get(name)!;
    } else {
      left = BigInt(parseLiteral(consume()));
    }

    while (peek() === "*" || peek() === "/") {
      const op = consume();
      const right = BigInt(parseTerm());
      if (op === "*") left *= right;
      else {
        if (right === 0n) throw new Error("Division by zero");
        left /= right;
      }
    }
    return normalizeResult(left);
  }

  function parseExpr(): number | bigint {
    let left = BigInt(parseTerm());
    while (peek() === "+" || peek() === "-") {
      const op = consume();
      const right = BigInt(parseTerm());
      if (op === "+") left += right;
      else left -= right;
    }
    return normalizeResult(left);
  }

  // Parse a statement: either `let name : Type = expr ;` or just an expression followed by optional `;`
  function parseStatement(): number | bigint {
    if (peek() === "let") {
      consume("let");       // let
      const name = consume(); // variable name
      consume(":");         // :
      consume();            // type annotation (e.g., U8, I16) - we ignore it for evaluation
      consume("=");         // =
      const value = BigInt(parseExpr());
      scope.set(name, value);
      if (peek() === ";") consume(";");
    } else {
      parseExpr();
      if (peek() === ";") consume(";");
    }
    return 0; // Statement result is ignored except for the last expression in a block
  }

  const result = parseExpr();

  if (pos < tokens.length) {
    throw new Error("Invalid format");
  }

  return result;
}

